var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"녀석의 존재가 세계침식률을 가속시킬 가능성은 얼마나 되지?","JPN":"やつの存在が世界侵食率を加速させる可能性はどれくらいだ？","ENG":"How likely is it that its presence will accelerate the Global Corruption rate?","TWN":"那傢伙的存在，加速世界侵蝕的可能性有多大？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄. 아직도 양자 위상차에 의한 이변이 일어나지 않는 걸 보면 특별히 문제는 없어 보이는군.","JPN":"そうだな。まだ量子位相差による異変が起きていないことからして、これと言った問題はなさそうだ。","ENG":"Hard to say. But since there's been no disturbance caused by quantum phase difference, I'd say we're in the clear for now.","TWN":"嗯，從目前看來，量子衛星引起的變異還沒有發生，所以應該沒有特別的問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…놈에게 문제가 생기면 바로 불러라.","JPN":"……やつに問題が生じたらすぐに呼べ。","ENG":"…If something goes wrong, call me immediately.","TWN":"…如果他有問題，馬上叫我。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"몸 상태는 어떤가?","JPN":"体の調子はどうかね？","ENG":"How's your condition?","TWN":"你的身體狀況如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"허수공간에서 8년을 보냈다면 후유증이 남을 법도 한데 말이야.","JPN":"8年もの時間を虚数空間で過ごすと、後遺症が残ってもおかしくはないのだが。","ENG":"Spending eight years in the imaginary space, I'd expect some lasting side effects.","TWN":"在虛數空間待了8年，應該會留下後遺症才對。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 육신은 멀쩡하오. 부끄럽게도 말이지.","JPN":"恥ずかしながら某の肉体はなんともない。","ENG":"My body's intact. Shamefully so, in fact.","TWN":"我的身體沒事。說起來有點丟臉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내겐 우물에서 있었던 일들이 방금 전처럼 생생하여… 설명을 듣기 전까진 그렇게 많은 시간이 흐른 줄도 몰랐소.","JPN":"某にとっては井戸での出来事がつい先程のように鮮明で……説明を聞くまでは、そこまで長い時間が過ぎていたとは気づかなかった。","ENG":"Everything that happened in the Well still feels as vivid as moments ago… I didn't realize how much time had passed until you told me.","TWN":"井裡發生的事，對我來說就像剛才一樣鮮明… 在聽你解釋之前，我根本不知道過了這麼久。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이해하네. 8년이란 시간은 이 세계가 허수공간을 표류하던 자네의 존재를 배제한 채 흘려보낸 것이니까.","JPN":"なるほど。その8年は、虚数空間を漂流していた君の存在が排除されたまま、この世界が経験したもの。","ENG":"I understand. For this world, those eight years passed without you, while you drifted in imaginary space.","TWN":"我能理解。8年的時間，是這個世界在排除了你在虛數空間漂流的存在後流逝的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"엄밀히 따지면, 자네가 속한 시간은 1초도 뒤바뀌지 않은 셈이지.","JPN":"厳密にいうと、君が属した時間は1秒も変わっていないということだ。","ENG":"But your own timeline, strictly speaking, hasn't skipped a second.","TWN":"嚴格來說，你所屬的時間並沒有改變一秒。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"관리자님, 말씀하신 먹구름 발생 주기를 분석해봤습니다만…","JPN":"最高管理者、言われた通り墨雲の発生周期を分析しましたが……","ENG":"Administrator, I ran the analysis on the dark cloud frequency you mentioned–","TWN":"管理者，我分析了你所說的墨雲發生週期…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L20_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"아, 실례했습니다. 다른 분과 대화 중이신 줄 몰랐네요.","JPN":"あ、失礼いたしました。他の方とのお話中だとは知らず……","ENG":"Ah, I'm sorry. I didn't realize you were speaking with someone.","TWN":"啊，不好意思。我不知道你正在和別人說話。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮네.","JPN":"大丈夫だ。","ENG":"It's fine.","TWN":"沒關係。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 분석 결과는 어떻지?","JPN":"それで、分析結果は？","ENG":"So, what did you find?","TWN":"那麼，分析結果如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"범이 힘의 갈무리를 거의 끝낸 것 같습니다. 이 진행속도라면 정확히 15일 뒤가 한계점이 될 겁니다.","JPN":"虎は力の収束をほぼ終えているようです。この進み具合なら、ちょうど15日後が限界点となるでしょう。","ENG":"The Tiger is nearly finished consolidating its strength. At this rate, the tipping point will hit in exactly fifteen days.","TWN":"老虎似乎已經快要完成力量的收納了。按照這個進度，極限點將在15天後到來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…동월?","JPN":"……トウゲツ？","ENG":"…Dongwol?","TWN":"…佟月？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"자네! 살아있었군!","JPN":"そなた、生きておったか！","ENG":"You're alive!","TWN":"你！你還活著！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"누구시죠? 제 이름은 어떻게…","JPN":"どちら様ですか？　どうしてボクの名前を……","ENG":"Um, do I know you? How do you know my name…?","TWN":"你是誰？你怎麼知道我的名字…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국에서 근무하던 옛 요원일세. 우릴 돕기 위해 지금 막 관리국에 복귀했지.","JPN":"管理局に勤めていた昔の要員だ。我々に協力するために管理局に復帰したばかりでな。","ENG":"He's a former agent. Just rejoined the Administration to help us.","TWN":"我是曾在管理局工作過的前特工。為了幫助我們，我剛回到管理局。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"근황을 얘기하다 자네가 관리국에 얼마나 큰 도움이 되고 있는지 얘기하고 있었어.","JPN":"近況を伝え、君がいかに管理局にとって力になってくれているか、話していたのだよ。","ENG":"We were just talking about you, actually. About how much help you've been.","TWN":"我正在聊你的近況，說你在管理局給了我們多大的幫助。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"…그렇습니까? 좀 쑥스럽네요.","JPN":"……そうですか。少し恥ずかしいですね。","ENG":"…Really? I'm feeling shy.","TWN":"…是嗎？真有點不好意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관측을 계속해주게. 이상 상황이 발생하면 지금처럼 내게 바로 보고해주고.","JPN":"観測を続けてくれ。異常事態が発生したら、こうしてすぐに私に報告するように。","ENG":"Keep observing. Report to me immediately if anything unusual happens.","TWN":"繼續觀察。如果發生異常狀況，就像剛才一樣馬上向我報告。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"알겠습니다.","JPN":"かしこまりました。","ENG":"Understood.","TWN":"明白了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"저기.","JPN":"あの。","ENG":"Hey.","TWN":"那個。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"돌아와 주셔서 감사합니다.","JPN":"帰ってきてくださってありがとうございます。","ENG":"Thank you for coming back.","TWN":"謝謝你回來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"지금 관리국은 한 사람의 도움이 정말 절실한 상황이거든요.","JPN":"今の管理局は、一人一人の助けが切実なんです。","ENG":"The Administration really needs all the help it can get right now.","TWN":"現在的管理局，真的非常需要一個人的幫助。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"관리국 삼군문 별동대의… 서생이라 하네.","JPN":"管理局三軍門別働隊の……ショウだ。","ENG":"I am Seosaeng… Member of the Administration's Trivanguard Special Task Unit.","TWN":"我是管理局三軍門先鋒隊的… 書生。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"종말대응국 환경분석과의 동월입니다.","JPN":"終末対応局の環境分析課所属、トウマ・トウゲツと申します。","ENG":"Dongwol. Environmental Analysis, Department of Doomsday Response.","TWN":"我是末日應對局環境分析科的佟月。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DONGWAL_NPC_BOY_14","text":{"KOREA":"남은 시간동안 잘 부탁드려요, 서생 씨.","JPN":"残りの間よろしくお願いします、ショウさん。","ENG":"I look forward to working with you, Seosaeng.","TWN":"請多多關照，書生。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정보 오염이라고 한다네.","JPN":"情報汚染、だと思われる。","ENG":"What you've witnessed is called data corruption.","TWN":"這叫做資訊污染。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"범이 일으킨 현실개변의 영향으로, 저 아이뿐만 아니라 이 세상에 자네의 존재를 기억하는 사람은 이제 없을 거야.","JPN":"虎が起こした現実改変の影響だ。あの子だけではなく、今のこの世界に君の存在を覚えている者は……もういないだろう。","ENG":"Because the Tiger caused a change in reality, no one in this world remembers you anymore. Not even that boy.","TWN":"受到老虎引起的現實改變影響，不僅是這個孩子，這個世界上已經沒有人記得你的存在了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…내가 없이도 훌륭한 학자가 되었구려.","JPN":"……某がいなくても、立派な学者になったのだな。","ENG":"…Even without me, he's become an outstanding scholar.","TWN":"…即使沒有我，你也成為了一位優秀的學者。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"8년의 시간이 흘렀다는 말이 이제야 실감이 나는군.","JPN":"8年が過ぎたという実感が、やっと沸いてきた。","ENG":"I suppose it's finally sinking in. Eight years really did pass.","TWN":"8年時光流逝這件事，現在才有了真實感。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"세상이 지금 얼마나 심각한 상황에 놓였는지… 감히 물어봐도 되겠소?","JPN":"今世界が置かれた状況がどれほど深刻なのか……説明を聞かせてもらえぬか。","ENG":"How bad is the situation now… if I may ask?","TWN":"現在世界的情況有多麼嚴重… 我可以問嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나름의 대책으로 막아보았지만, 범에게 큰 타격을 입었네.","JPN":"なんとか対策を立てて防いだものの、虎による被害は甚大だった。","ENG":"We've tried to hold the line, but the Tiger dealt us a devastating blow.","TWN":"我們用盡了辦法試圖阻止，但還是受到了老虎的重創。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 계획에 필요한 최소한의 인원을 제외하면 8년 사이에 전부 죽었다 봐도 무방하지.","JPN":"我々の計画に必要な最低限の人員を除けば、8年間に全人類が死亡したと言えるな。","ENG":"I can safely say that everyone who wasn't absolutely necessary to our plan died over the past eight years.","TWN":"除了我們計畫所需的最低限度的人員，8年來幾乎所有人都死了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"테라브레인의 연산을 총동원해 가까스로 종말을 유예하고 있지만, 이마저도 얼마 버티지 못할 걸세.","JPN":"テラブレインの演算を総動員し、辛うじて終末を先延ばしにしているが、そう長くはもたないだろう。","ENG":"We're barely delaying the end with all of Terrabrain's calculations, and even that won't last much longer.","TWN":"我們動用了特拉大腦的所有運算能力，勉強延後了末日，但這也撐不了多久。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇게 된 건… 전부 내 탓이오.","JPN":"こうなったのは……すべて某のせいだ。","ENG":"This… this is all my fault.","TWN":"會變成這樣… 都是我的錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내 어리석은 판단으로… 너무 큰 재앙을 이곳에 불러들였소.","JPN":"某の愚かな判断で……あまりにも大きすぎる災害を招いてしまった。","ENG":"My foolish decision… brought this catastrophe upon here.","TWN":"我的愚蠢判斷… 在這裡引發了如此巨大的災難。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"범이 깨어나고 세상이 이렇게 된 게, 자네의 잘못이라고 생각하나?","JPN":"虎が目覚め、世界がこうなったのが君のせいだと思うのか？","ENG":"You think the Tiger waking and the world falling apart is your fault?","TWN":"你認為，老虎甦醒，世界變成這樣，是你的錯嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"차라리 도망쳐 숨는 편이 나았을 거요.","JPN":"いっそのこと、逃げて隠れればよかったのだ。","ENG":"I should've run. Hidden away.","TWN":"或許逃跑躲起來會比較好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"기억을 되찾는 대신 현실에 안주했더라면, 상황이 지금만큼 나빠지진 않았을 테니.","JPN":"記憶を取り戻す代わりに、現実に安住していれば、状況がこれほど悪化することはなかったかもしれん。","ENG":"If I'd chosen to forget everything and settle into reality, maybe things wouldn't have turned out this bad.","TWN":"如果我選擇安於現實，而不是找回記憶，情況就不會變得這麼糟。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무슨 말인지 이해하네.","JPN":"君の言っていることは十分理解する。","ENG":"I get it.","TWN":"我明白你的意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자신의 판단 때문에 소중한 이들이 하나 둘 사라져갈 때…","JPN":"自分の判断のせいで、大切な者が犠牲になっていく姿を見ると……","ENG":"When you start losing people precious to you, due to your judgment…","TWN":"當你的判斷讓珍貴的人一個個消失時…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어차피 배반당할 노력이라면 아무것도 하지 않는 편이 낫겠다는 생각이 들곤 하지.","JPN":"どうせ裏切られる努力なら、最初から何もしないほうがいい……と思ってしまうものだ。","ENG":"You can't help but wonder if it would've been better to do nothing at all, than to try and fail.","TWN":"你會覺得，既然努力都會被背叛，那什麼都不做會更好。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 말이야…","JPN":"だが……","ENG":"But you know…","TWN":"但是…"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좌절감에 사로잡힌 순간에도 무정한 시계의 초침은 쉼 없이 흐르더군.","JPN":"挫折感に打ちひしがれている間にも、時間は無情にも流れ続ける。","ENG":"Even in that despair, time keeps ticking, whether you're breathing or breaking.","TWN":"在被挫折感支配的瞬間，無情的秒針依舊不停地流逝。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"회한에 사무쳐 한숨을 내쉴 때도, 어리석었던 나 자신을 책망할 때도, 분에 못 이겨 책상을 내려치는 순간에도…","JPN":"後悔の念に駆られてため息をつく時も、愚かだった自分を責める時も、怒りに耐えきれず机を拳で叩く時も……","ENG":"Even as you sigh in regret, curse your past, slam your desk in anger…","TWN":"在充滿悔恨地嘆氣時，在責備愚蠢的自己時，在因憤怒而捶打桌子的瞬間…"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 훗날 간절히 원하게 될지도 모를 그 1분 1초가 허비되고 있다는… 그런 생각이 문득 들더군.","JPN":"ある時、ふとこう思ったんだ。もしかすると今の私は、後日の自分が切実に必要とする1分1秒を、無駄にしているのでは……と。","ENG":"You realize that you're wasting the very seconds you might someday desperately wish… to get back.","TWN":"我突然想到，那些未來可能會迫切需要的每一分每一秒，正在被浪費。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그때부터 난, 그 시간을 넋 놓고 허비하지 않기로 했다네.","JPN":"それから私は、その時間を無駄にしないと決めた。","ENG":"That's when I decided. I wouldn't waste another second.","TWN":"從那時起，我就決定，不再任由時間白白流逝。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후회나 포기 같은 건, 그런 걸 할 수 없게 된 뒤에 해도 늦지 않으니까.","JPN":"後悔したり諦めたりすることは、何もできなくなってからでも遅くない。","ENG":"Regret and surrender, save those for when you have no other choice.","TWN":"後悔或放棄這種事，等到無法做到的時候再說也不遲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 돌아서려 했던 그 한 걸음 앞에…","JPN":"そうは思わないか？　引き返そうと思ったその地点の一歩先に……","ENG":"Maybe, just maybe, the ending you've been chasing…","TWN":"或許，就在你準備轉身離開的那一步前面…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 그토록 찾고 있던 결말이 있을지도 모르지 않나?","JPN":"切実に探し求めていた結末が待っているかもしれないぞ？","ENG":"Lies a single step past the point where you almost gave up. Don't you think?","TWN":"有我一直以來尋找的結局呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"포기하지 않는다 하여, 이미 떠나보낸 사람들이 살아 돌아오는 건 아니잖소.","JPN":"諦めないといって、去って行った人々が生き返るわけではあるまい。","ENG":"But even if I don't give up, that won't bring back the people I've lost.","TWN":"就算不放棄，那些已經離開的人也不會活著回來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런. 내 비장의 멘트가 자네에겐 별 효과가 없었던 모양이군.","JPN":"やれやれ。切り札としてとっておいた台詞が君には効き目がなかったようだな。","ENG":"Shucks. Guess my big speech didn't land the way I hoped.","TWN":"糟糕。我這招殺手鐧對你好像沒什麼效果。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"명달은 자네가 어떤 좌절을 겪어도 금방 기운을 차릴 거라던데 말이지.","JPN":"アカタツは、君ならどんな挫折を経験してもすぐ立ち直ると言っていたが。","ENG":"Myeongdal said you'd bounce back no matter what you went through.","TWN":"明達說過，無論你經歷什麼挫折，都能很快振作起來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장을 알고 있소?","JPN":"アカタツ隊長を知っているのか？","ENG":"You know Myeongdal?","TWN":"你認識明達隊長？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"알다마다.","JPN":"もちろんだ。","ENG":"Of course I do.","TWN":"當然。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대는 정보 오염의 영향을 받지 않는 건가?","JPN":"そなたは情報汚染の影響を受けないのか？","ENG":"Then you're not affected by data corruption?","TWN":"你沒有受到資訊污染的影響嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 좀 특이체질이라서 말이야.","JPN":"私は特異体質でな。","ENG":"I'm a bit of a special case, let's say.","TWN":"我體質比較特殊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 친구가 마지막 작전을 떠나며 남긴 부탁도 전부 기억하고 있지.","JPN":"最後の作戦に出る彼から頼まれたことも、すべて覚えている。","ENG":"I still remember every favor he asked me to carry out on his final mission.","TWN":"那個朋友在去執行最後的任務時，拜託我的事我都記得。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장이… 부탁을 남겼다고?","JPN":"アカタツ隊長の……頼み？","ENG":"Commander Myeongdal… left you a request?","TWN":"明達隊長… 留下了遺言？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"머잖아 범이 세상을 침범할 테니, 자네와 함께 그날을 대비해 달라고 말이야.","JPN":"近いうちに虎が世界を襲うだろうから、君と共に備えてほしいと言っていたよ。","ENG":"He knew the Tiger would rise again. He asked me to prepare for that day with you.","TWN":"他說老虎很快就會侵襲世界，所以請我與你一起為那天做準備。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그럼 명달 대장은… 내가 실패할 것을 알고 있었다는 건가?","JPN":"では、アカタツ隊長は……某が失敗することも全部知っていたということか？","ENG":"So… he knew I would fail?","TWN":"那麼明達隊長… 是知道我會失敗的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"불필요한 인과라는 건 없다네.","JPN":"不要な因果など存在しない。","ENG":"There's no such thing as a pointless causality.","TWN":"沒有無用的因果。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그것이 설령 시간을 되돌리는 터무니없는 짓이라 해도 말이야.","JPN":"たとえそれが時間を巻き戻すという無茶な行為だとしてもな。","ENG":"Even if it involves something as absurd as turning back time.","TWN":"即使那是逆轉時間這種荒謬的事。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장이 무슨 말을 했는지, 내가 알아도 되겠소?","JPN":"アカタツ隊長が何を言ったか聞いてもよいだろうか。","ENG":"Then, am I allowed to know what Commander Myeongdal said?","TWN":"明達隊長說了什麼，我可以知道嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"명달의 눈에는 그 사람의 최후가 보인다네. 그 몸속에 흐르는 특별한 피의 힘이지.","JPN":"アカタツには人の最期が見えるらしい。その体に流れる特殊な血による能力だ。","ENG":"Myeongdal could see a person's final fate. That was a gift from his blood.","TWN":"明達的眼睛能看見那個人的結局。這是他體內流淌的特殊血液的力量。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 내가 명달과 함께 이 계획을 추진하게 된 계기는… 연화의 죽음을 보았기 때문이야.","JPN":"そして私がアカタツと共にこの計画を進めることになったきっかけは……レンカの死を見たからだ。","ENG":"The reason I joined him in this plan… is because he saw Yeonhwa's death.","TWN":"而我與明達一起推動這個計畫的契機… 是因為我看見了蓮華的死亡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화의 죽음…?","JPN":"レンカの死……？","ENG":"Yeonhwa's death…?","TWN":"蓮華的死亡…？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"연화는 훗날 제 스승의 손에 죽을 걸세. 끝내 용혈의 번뇌를 극복하지 못하고 무너질 운명이지.","JPN":"レンカはいつか、己の師匠の手によって命を落とすことになる。龍血の煩悩を乗り越えられず、散りゆく運命だ。","ENG":"She'll be killed by her own master. Her Dragon Blood will drive her into a frenzy she can't control.","TWN":"蓮華會在未來死在她師父的手下。這是她最終無法克服龍血的煩惱而崩潰的命運。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그럴 리가. 연화는 범에게 죽었소.","JPN":"そんなわけがない。レンカは虎に殺された。","ENG":"That can't be. She died fighting the Tiger.","TWN":"這不可能。蓮華是被老虎殺死的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그게 틀렸다면 내가 지금껏 보고 겪은 현실은 모두 꿈이란 말인가?","JPN":"それが間違いなら、某が見て経験した現実はすべて夢なのか？","ENG":"If that's wrong, then was everything I experienced just a dream?","TWN":"如果那是錯的，那我至今所看到、經歷的現實，都只是夢嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 본 것 또한 틀림없는 현실일세.","JPN":"君が見たのは間違いなく現実だ。","ENG":"What you saw was reality.","TWN":"你所看到的也是真實的現實。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 데이터베이스에도 연화는 범에게 맞서다 전사한 것으로 기록되어 있지.","JPN":"管理局のデータベースにも、レンカは虎との戦いで戦死したと記録されている。","ENG":"Even the Administration's database records that she fell fighting the Tiger.","TWN":"管理局的資料庫也記錄了蓮華是在與老虎對抗中陣亡的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말인 즉, 지금 그녀는 운명에 없던 죽음을 맞았다는 뜻이야.","JPN":"つまり、彼女は運命にない死を迎えたということだ。","ENG":"Which means she died a death that wasn't written in fate.","TWN":"這也就是說，她現在的死亡，是命運中沒有的死亡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"운명에 없던 죽음이라고…?","JPN":"運命にない死……？","ENG":"A death not written in fate…?","TWN":"命運中沒有的死亡…？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"운명은 고무와 같아서 아무리 힘을 주고 잡아당겨도, 본래의 형태로 돌아온다네.","JPN":"運命はゴムのようでね、どれだけ力強く引っ張っても元の形に戻る。","ENG":"Fate is like rubber. You can stretch it out of shape, but it'll snap back eventually.","TWN":"命運就像橡皮筋，無論你如何用力拉扯，最終都會回到它原來的形狀。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무리 운명을 바꾸려 해도, <color=#ffd34c>또다른 계기</color>가 그 뒤틀린 운명을 결국 제자리로 되돌려 놓는다는 거지.","JPN":"いくら運命を変えようとしても、<color=#ffd34c>別のきっかけ</color>が捻じれた運命をあるべき姿に戻すということさ。","ENG":"Change fate all you want, but <color=#ffd34c>another trigger</color> will always come along to put the twisted fate back into place.","TWN":"無論如何試圖改變命運，<color=#ffd34c>另一個契機</color>最終都會將扭曲的命運拉回正軌。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 명달과 나는…","JPN":"そしてアカタツと私は……","ENG":"Myeongdal and I…","TWN":"而我和明達…"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 계기가 자네일 것이라는 데 모든 걸 걸기로 했다네.","JPN":"そのきっかけが君であると信じ、すべてを賭けてみることにした。","ENG":"We bet everything that you might be that trigger.","TWN":"我們決定將一切賭在，那個契機就是你。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그 말이 사실이라 해도, 아직 이해가 되지 않는 점이 하나 있소.","JPN":"……その話が事実だとして、まだ1つ理解できない点がある。","ENG":"…Even if that's true, there's still one thing I don't understand.","TWN":"…即使你說的是真的，還有一點我無法理解。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"결국 모든 게 운명대로 흘러가고 마는 거라면… 연화는 어째서 자신의 운명을 벗어난 선택을 한 것인지.","JPN":"結局すべてが運命通りに進んでいるなら……レンカはなぜ自分の運命から外れた選択に至ったのだ？","ENG":"If fate always returns to its path… then why did Yeonhwa choose something outside of it?","TWN":"如果一切最終都會按照命運發展… 那蓮華為什麼要做出違背自己命運的選擇？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 아이가 왜 그런 선택을 했는진 나도 모른다네.","JPN":"あの子がなぜそんな選択をしたのかは私にも分からない。","ENG":"Why she chose to do what she did, I don't know.","TWN":"她為什麼會做出那樣的選擇，我也不知道。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"주어진 운명을 거슬러서라도 결말을 바꾸고 싶었던… 그 운명의 주인만이 알고 있겠지.","JPN":"与えられた運命に逆らってでも結末を変えたかった……当の本人のみぞ知ることだろう。","ENG":"Only she, the one who defied her fate, could ever… answer that.","TWN":"只有那個違背既定命運，也想改變結局的… 命運的主人自己才知道。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"여긴… 어디지?","JPN":"ここは……どこだろう？","ENG":"Where… am I?","TWN":"這裡是… 哪裡？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_15"},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"마지막엔 사부랑 과거로 갔다가 몸이 사라져서…","JPN":"最後は師匠と過去に行って、体が消えて……","ENG":"The last thing I remember is going to the past with Master, and then my body just faded away…","TWN":"最後我跟師父回到過去，然後身體就消失了…"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_16"},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"…나, 죽었구나.","JPN":"……私、死んだんだ。","ENG":"…So I really did die.","TWN":"…我死了嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_17"},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"바람을 타고 사람들의 웃음소리가 들려.","JPN":"風に乗って人々の笑い声が聞こえる。","ENG":"I hear laughter, carried by the wind.","TWN":"我聽到了風中傳來人們的笑聲。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_18"},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"주변에 좋은 일이 있는 모양이네.","JPN":"この辺で何かいいことがあるみたい。","ENG":"Sounds like something happy is happening nearby.","TWN":"周圍好像有什麼好事發生。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_19"},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"뭐야. 결혼식이구나.","JPN":"なんだ、結婚式か。","ENG":"Huh? A wedding?","TWN":"什麼啊。原來是婚禮。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_20"},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"주마등이라기엔 난 결혼한 적이 없는데?","JPN":"走馬灯にしては……私は結婚してないけど？","ENG":"It can't be a flashback. I've never even been married.","TWN":"說是走馬燈，但我沒有結過婚啊？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_21"},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"어? 그런데 저기 있는 남자는…?","JPN":"あれ？　あそこの男の人って……？","ENG":"Hold on… that man over there…","TWN":"嗯？但是那裡的男人是…？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_22"},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…사부?!","JPN":"……師匠！？","ENG":"…Master?!","TWN":"…師父？！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_23"},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_NPC_PAST_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_48"},{"id":"L41_1","type":"dialog","speaker":"YEONHWA_NPC_PAST_NULL","text":{"KOREA":"갑자기 어딜 보는 거야?","JPN":"急にどこを見てるの？","ENG":"What are you staring at all of a sudden?","TWN":"你突然在看哪裡？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_35"},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_NPC_PAST_NULL","text":{"KOREA":"…아무것도 아닐세. 내가 잘못 들은 거겠지.","JPN":"……何でもない。某の聞き間違いであろう。","ENG":"…Nothing. Must've imagined it.","TWN":"…沒什麼。我聽錯了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_49"},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_NPC_PAST_NULL","text":{"KOREA":"당신, 대기석에서도 연구자료 읽었다며?","JPN":"あなた、待機してる間も研究資料を読んでたって聞いたわ。","ENG":"You were reading research notes in the waiting room too, weren't you?","TWN":"你說你連在待機區都在看研究資料？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_36"},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_NPC_PAST_NULL","text":{"KOREA":"나전 천갑을 개선할 방안이 떠올랐거든.","JPN":"螺鈿天甲を改善するいい方法を思いついてな。","ENG":"A new idea came to me about how to improve the Heavenly Inlaid Armor.","TWN":"因為我想到了一個改善螺鈿天甲的方法。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_50"},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_NPC_PAST_NULL","text":{"KOREA":"하아, 못 말려. 누가 서생 아니랄까봐. 결혼식장에서도 일을 하고 있네.","JPN":"はあ、あなたって人はとことん学者さんなんだね。結婚式場でも仕事だなんて。","ENG":"*Sigh* Of course. Only you would be working even at your own wedding.","TWN":"唉，拿你沒辦法。不愧是書生。竟然連在婚禮上都在工作。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_37"},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_NPC_PAST_NULL","text":{"KOREA":"봐주게. 미래에 우리 아이가 살아갈 세상이 좀 더 평화롭길 바라는 거니까.","JPN":"大目に見てくれ。我らの子が生きる世界がより平和であることを願ってのことゆえ。","ENG":"Forgive me. I just want to help build a world where our child can live in peace.","TWN":"體諒一下吧。我只是希望我們孩子未來的世界能更和平。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_51"},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_NPC_PAST_NULL","text":{"KOREA":"지금 당장 당신을 차버리면 세상이 더 평화로워지겠네.","JPN":"今あなたを振ったら、世界はもっと平和になるはずよ。","ENG":"If I dumped you right now, the world might actually become more peaceful.","TWN":"我現在把你甩了，世界就會更和平。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_38"},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_NPC_PAST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_52"},{"id":"L49_1","type":"dialog","speaker":"YEONHWA_NPC_PAST_NULL","text":{"KOREA":"뭘 그렇게 뚫어져라 쳐다봐?","JPN":"何ジロジロ見てるの？","ENG":"Why are you looking at me like that?","TWN":"你幹嘛一直盯著我看？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_39"},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_NPC_PAST_NULL","text":{"KOREA":"오늘따라 무척 아름답군.","JPN":"今日はいつもよりも美しいな。","ENG":"You look especially beautiful today.","TWN":"你今天特別美麗。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_53"},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_NPC_PAST_NULL","text":{"KOREA":"…그거 알아? 당신 오늘따라 재수없는 거.","JPN":"……ねえ、知ってる？　今日のあなたはいつもよりむかつくってこと。","ENG":"…You know what? That's the most annoying thing you've ever said.","TWN":"…你知道嗎？你今天特別討厭。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_40"},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저 신부는 연화 언니를 닮았어.","JPN":"あの花嫁さん、レンカさんに似てる。","ENG":"That bride. She looks like Yeonhwa.","TWN":"那個新娘長得好像蓮華姊姊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_24"},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"두 사람 모두… 정말 잘 어울리는 한 쌍이네.","JPN":"2人とも……本当にお似合いのカップルだなあ。","ENG":"They look… perfect together.","TWN":"他們兩個… 真是一對璧人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_25"},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럼 이건, 사부의 전생인 건가?","JPN":"じゃあこれは師匠の前世ってことかな？","ENG":"Is this Master's past life?","TWN":"那這就是師父的前世嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_26"},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"몇 번이고 다시 태어나 서로를 사랑하게 될 운명이라니. 꼭 동화 같아.","JPN":"何度も生まれ変わってもお互いを愛する運命だなんて……おとぎ話みたい。","ENG":"Fated to fall in love over and over through countless lifetimes. It's like something out of a storybook.","TWN":"無論輪迴幾次都會再次相愛，這簡直就像童話故事一樣。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_27"},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…하아, 그에 비하면 난…","JPN":"……はあ、それに比べると私は……","ENG":"…*Sigh* Compared to that, I–","TWN":"…唉，相比之下，我…"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_28"},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_29"},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"갑자기 웬 구름이…","JPN":"どうして急に雲が……","ENG":"Clouds, all of a sudden…?","TWN":"怎麼突然出現烏雲…"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_30"},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"틀려. 이건 평범한 구름이 아니라…!","JPN":"違う、これは普通の雲じゃない……！","ENG":"No. Those aren't normal clouds…!","TWN":"不對。這不是普通的烏雲…！"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_31"},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부?","JPN":"師匠？","ENG":"Master?","TWN":"師父？"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_32"},{"id":"L14_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"위험해! 뒤를 봐!","JPN":"危ない！　後ろを見て！","ENG":"Look out! Behind you!","TWN":"危險！看後面！"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_33"},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_NPC_PAST_NULL","text":{"KOREA":"서생, 안돼!!","JPN":"ショウ、ダメ！！","ENG":"Seosaeng, no!!","TWN":"書生，不要！！"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_148"},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…어째서야…?","JPN":"……どうして……？","ENG":"…Why…?","TWN":"…為什麼會這樣…？"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_34"},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"왜 모두가 행복해야 할 결혼식에서… 이런 끔찍한 일이…","JPN":"どうして、みんなが幸せなはずの結婚式で……こんな残酷なことが……","ENG":"Why did something this awful happen…? At a wedding where everyone's supposed to be happy…?","TWN":"為什麼在大家本該幸福的婚禮上… 會發生這麼可怕的事…"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_35"},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"운명에는 눈과 귀가 없다. 그래서 좋음도 나쁨도 가리지 않아.","JPN":"運命は目も耳も持たない。それゆえに、良し悪しを区別しない。","ENG":"Fate has no eyes or ears. It doesn't care what's good or bad.","TWN":"命運沒有眼睛和耳朵。所以它不分好壞。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_149"},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"천생연분이 운명이듯, 가장 행복한 순간의 죽음 또한 운명인 것이지.","JPN":"赤い糸で結ばれた関係が運命であるように、最も幸せな瞬間に死を迎えることも、また運命。","ENG":"Just as soulmates are fated, so too is dying at your happiest moment.","TWN":"天作之合是命運，在最幸福的瞬間死去也是命運。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_150"},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…이런 비극이 운명이라고?","JPN":"……こんな悲劇が運命？","ENG":"…You call this tragedy fate?","TWN":"…這種悲劇也是命運？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_36"},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"왜 그런 운명이 존재하는 거죠?","JPN":"なんでそんな運命が存在するんですか？","ENG":"Why would a fate like that even exist?","TWN":"為什麼會有這樣的命運存在？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_37"},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"호랑이님께서 원하셨기 때문이다.","JPN":"虎様がそれをお望みだから。","ENG":"Because that's what the Tiger wanted.","TWN":"因為老虎想要。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_151"},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"호랑이님은 고통받는 영혼을 얻기 위해, 우리에게 땅내림의 저주를 내렸어.","JPN":"虎様は苦しむ魂を手に入れるために、私たちにチガカリの呪いを授けた。","ENG":"The Tiger laid the curse of the Earthbound upon us to harvest suffering souls.","TWN":"老虎為了得到痛苦的靈魂，給了我們地脈之力的詛咒。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_152"},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"더는 발버둥치지 못하고 지쳐, 스스로 범의 입안에 기어 들어갈 때까지.","JPN":"足掻くこともできず疲れ果てて、自らの足で虎の口の中へ入るまで続く呪いを。","ENG":"Until we collapse in exhaustion, unable to resist, and crawl willingly into its jaws.","TWN":"直到我們無法再掙扎，疲憊不堪，自願爬進老虎的嘴裡。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_153"},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그런데도 호랑이님이라고?","JPN":"それなのに、「虎様」？","ENG":"You still refer to it with reverence?","TWN":"你為何要聽命於牠？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_38"},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저주로 자기 인생을 망가뜨린 괴물을 섬기다니! 왜 그렇게 되어버린 거죠?","JPN":"呪いで自分の人生をめちゃくちゃにした化け物に仕えるなんて！　どうしてそうなってしまったんですか？","ENG":"That monster ruined your life, and you still serve it? Why?","TWN":"侍奉一個用詛咒毀了自己人生的怪物！你為什麼會變成這樣？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_39"},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"고통은 살고자 하기에 감내하는 것.","JPN":"苦しみは生きるために耐えるもの。","ENG":"Pain is what we endure for the sake of living.","TWN":"痛苦是為了活下去而忍受的。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_154"},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"삶을 저버린 지금의 내겐… 그런 원한 따위 아무런 의미도 없어.","JPN":"生を捨てた今の私に……そんな恨みなど、なんの意味もない。","ENG":"But I've already thrown my life away… Such grudge means nothing to me now.","TWN":"對現在已經放棄生命的我來說… 那種怨恨毫無意義。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_155"},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"호랑이님께서 세상을 전부 삼키고 나면, 그 뒤엔 너희의 혼을 취하실 거야.","JPN":"虎様は世界をすべて呑み込んだ後、あなたたちの魂も召し上がるはず。","ENG":"When the Tiger swallows the world whole, your souls will be next.","TWN":"等老虎吞噬了整個世界，牠就會取走你們的靈魂。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_156"},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그때가 되면, 서생도 비로소 우리와 함께 하게 되겠지.","JPN":"その日が来れば、ようやくショウも私たちと1つになれるでしょう。","ENG":"And when that day comes, Seosaeng will finally join us.","TWN":"到那時，書生也會終於和我們在一起。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_157"},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부가… 아직 살아있다고?","JPN":"師匠が……まだ生きてる？","ENG":"Master's… still alive?","TWN":"師父… 還活著嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_JWIBUL_IN_CUTSCENE_40"},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"관리국엔 여러 모로 귀찮은 자가 있지. 이 변수는 호랑이님조차 간파하지 못하셨다.","JPN":"管理局には色々と厄介な者がいる。あの存在については虎様すらも見抜けなかった。","ENG":"There's someone in the Administration who keeps meddling. Even the Tiger didn't see this variable coming.","TWN":"管理局有幾個麻煩的傢伙。就連老虎也沒能看穿這個變數。"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_158"},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만, 결국 시간문제일 뿐이야.","JPN":"でも、結局は時間の問題に過ぎない。","ENG":"But it's only a matter of time.","TWN":"但最終，這只是時間問題。"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_159"}]`);export{e as default};